import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Eye, EyeOff, Cpu, Zap } from 'lucide-react';

/* Autofill bg colour — must be a real hex/rgb, CSS vars don't work inside webkit inset shadow */
const AUTOFILL_BG   = '#111318';  /* matches --card-bg / --bg-secondary in dark theme */
const AUTOFILL_TEXT = '#ffffff';

const LoginPage = () => {
  const [email, setEmail]       = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading]   = useState(false);
  const [focused, setFocused]   = useState(null);

  const { login } = useAuth();
  const navigate  = useNavigate();

  const [scanKey, setScanKey] = useState(0);
  useEffect(() => { setScanKey(k => k + 1); }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!email || !password) return toast.error('Please enter your credentials.');
    setLoading(true);
    try {
      await login(email, password);
      toast.success('Welcome back to Finify!');
      navigate('/dashboard');
    } catch {
      toast.error('Invalid credentials. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  /* Shared autofill-proof input style */
  const inputStyle = (extra = {}) => ({
    width: '100%',
    boxSizing: 'border-box',
    WebkitBoxShadow: `0 0 0px 1000px ${AUTOFILL_BG} inset`,
    WebkitTextFillColor: AUTOFILL_TEXT,
    caretColor: 'var(--accent-primary)',
    ...extra,
  });

  return (
    <>
      {/*
        Use flex:1 + min-height:0 so this div fills whatever space the layout
        leaves after the sticky navbar — no more card being pushed or stretched.
      */}
      <div style={{
        flex: 1,
        minHeight: 0,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: '2rem 1rem',
        boxSizing: 'border-box',
        position: 'relative',
        background: 'radial-gradient(ellipse at 50% 40%, var(--bg-secondary) 0%, var(--bg-main) 70%)',
      }}>

        {/* Ambient glows — fixed so they never affect layout */}
        <div aria-hidden="true" style={{
          position: 'fixed', top: '-80px', left: '-80px',
          width: '320px', height: '320px',
          background: 'var(--accent-glow)', borderRadius: '50%',
          filter: 'blur(80px)', opacity: 0.5, pointerEvents: 'none', zIndex: 0,
        }} />
        <div aria-hidden="true" style={{
          position: 'fixed', bottom: '-60px', right: '-60px',
          width: '260px', height: '260px',
          background: 'var(--accent-glow)', borderRadius: '50%',
          filter: 'blur(90px)', opacity: 0.25, pointerEvents: 'none', zIndex: 0,
        }} />

        {/* ── Login Card ── */}
        <div
          className="reveal-node"
          style={{
            position: 'relative',
            zIndex: 1,
            width: '100%',
            maxWidth: '400px',                     /* compact width */
            padding: '2rem',
            borderRadius: '20px',
            backdropFilter: 'blur(20px)',
            WebkitBackdropFilter: 'blur(20px)',
            background: 'var(--surface-glass)',
            border: '1px solid var(--surface-border)',
            boxShadow: 'var(--shadow-elevated)',
            overflow: 'hidden',
            transition: 'box-shadow 0.4s ease, border-color 0.4s ease',
          }}
          onMouseEnter={e => {
            e.currentTarget.style.boxShadow    = '0 0 40px var(--accent-glow), var(--shadow-elevated)';
            e.currentTarget.style.borderColor  = 'var(--accent-primary)';
          }}
          onMouseLeave={e => {
            e.currentTarget.style.boxShadow    = 'var(--shadow-elevated)';
            e.currentTarget.style.borderColor  = 'var(--surface-border)';
          }}
        >
          {/* Laser scanner */}
          <span key={scanKey} className="animate-laser" aria-hidden="true" />

          {/* ── Header ── */}
          <div style={{ textAlign: 'center', marginBottom: '1.75rem' }}>
            <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '0.8rem' }}>
              <div style={{
                width: '46px', height: '46px', borderRadius: '13px',
                background: 'var(--accent-muted)',
                border: '1px solid var(--accent-primary)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                boxShadow: '0 0 18px var(--accent-glow)',
              }}>
                <Cpu size={20} color="var(--accent-primary)" />
              </div>
            </div>
            <h1 style={{
              fontSize: '1.4rem', fontWeight: 300, letterSpacing: '-0.02em',
              color: 'var(--text-primary)', margin: '0 0 0.3rem',
            }}>
              Welcome Back
            </h1>
            <p style={{
              fontSize: '0.58rem', textTransform: 'uppercase',
              letterSpacing: '0.22em', color: 'var(--text-muted)', margin: 0,
            }}>
              Sign in to access your node
            </p>
          </div>

          {/* ── Form ── */}
          <form
            onSubmit={handleSubmit}
            noValidate
            style={{ display: 'flex', flexDirection: 'column', gap: '0.9rem' }}
          >
            {/* Email */}
            <div>
              <label htmlFor="login-email" style={{
                display: 'block', fontSize: '0.58rem', fontWeight: 700,
                textTransform: 'uppercase', letterSpacing: '0.18em',
                color: focused === 'email' ? 'var(--accent-primary)' : 'var(--text-muted)',
                marginBottom: '0.35rem', transition: 'color 0.2s ease',
              }}>
                Email Address
              </label>
              <input
                id="login-email"
                type="email"
                placeholder="operator@finify.ai"
                value={email}
                onChange={e => setEmail(e.target.value)}
                onFocus={() => setFocused('email')}
                onBlur={() => setFocused(null)}
                className="cyber-input"
                autoComplete="email"
                required
                style={inputStyle()}
              />
            </div>

            {/* Password */}
            <div>
              <label htmlFor="login-password" style={{
                display: 'block', fontSize: '0.58rem', fontWeight: 700,
                textTransform: 'uppercase', letterSpacing: '0.18em',
                color: focused === 'password' ? 'var(--accent-primary)' : 'var(--text-muted)',
                marginBottom: '0.35rem', transition: 'color 0.2s ease',
              }}>
                Master Key
              </label>
              <div style={{ position: 'relative' }}>
                <input
                  id="login-password"
                  type={showPass ? 'text' : 'password'}
                  placeholder="••••••••"
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  onFocus={() => setFocused('password')}
                  onBlur={() => setFocused(null)}
                  className="cyber-input"
                  autoComplete="current-password"
                  required
                  style={inputStyle({ paddingRight: '3rem' })}
                />
                <button
                  type="button"
                  onClick={() => setShowPass(v => !v)}
                  aria-label={showPass ? 'Hide password' : 'Show password'}
                  style={{
                    position: 'absolute', right: '0.875rem', top: '50%',
                    transform: 'translateY(-50%)',
                    background: 'none', border: 'none', padding: 0,
                    cursor: 'pointer', color: 'var(--text-muted)',
                    display: 'flex', alignItems: 'center',
                    transition: 'color 0.2s ease',
                  }}
                  onMouseEnter={e => e.currentTarget.style.color = 'var(--accent-primary)'}
                  onMouseLeave={e => e.currentTarget.style.color = 'var(--text-muted)'}
                >
                  {showPass ? <EyeOff size={15} /> : <Eye size={15} />}
                </button>
              </div>
            </div>



            {/* Submit */}
            <button
              type="submit"
              className="cyber-btn"
              disabled={loading}
              style={{ marginTop: '0.2rem' }}
            >
              {loading
                ? <><Zap size={13} style={{ animation: 'pulse 1s ease-in-out infinite' }} /> SYNCHRONIZING...</>
                : 'Access Node'
              }
            </button>
          </form>

          {/* ── Footer ── */}
          <div style={{
            marginTop: '1.25rem', paddingTop: '1rem',
            borderTop: '1px solid var(--surface-border)',
            textAlign: 'center',
          }}>
            <p style={{
              fontSize: '0.58rem', textTransform: 'uppercase',
              letterSpacing: '0.2em', color: 'var(--text-muted)', margin: 0,
            }}>
              No account?{' '}
              <Link to="/register" style={{
                color: 'var(--accent-primary)', textDecoration: 'none',
                fontWeight: 700, transition: 'opacity 0.2s ease',
              }}
                onMouseEnter={e => e.currentTarget.style.opacity = '0.7'}
                onMouseLeave={e => e.currentTarget.style.opacity = '1'}
              >
                Create one
              </Link>
            </p>
          </div>
        </div>
      </div>
    </>
  );
};

export default LoginPage;
